const EXAMPLES = [
  'Server is down, users cannot log in',
  'Unauthorized login attempt detected on your account',
  'Low battery: 5% remaining, please charge now',
  'Your package has been delivered',
  'Flash sale — 50% off today only!',
  'John liked your photo',
  'Your bank account has been locked',
  'New message from Mom',
];

function sigmoid(x: number) { return 1 / (1 + Math.exp(-x)); }
function tokenize(text: string) { return text.toLowerCase().match(/\b\w+\b/g) || []; }
function getNgrams(tokens: string[], minN: number, maxN: number) {
  const ngrams: string[] = [];
  for (let n = minN; n <= maxN; n++)
    for (let i = 0; i <= tokens.length - n; i++)
      ngrams.push(tokens.slice(i, i + n).join(' '));
  return ngrams;
}

function runClassifier(text: string, model: any) {
  const tokens = tokenize(text);
  const [minN, maxN] = model.ngram_range;
  const ngrams = getNgrams(tokens, minN, maxN);
  const counts: Record<string, number> = {};
  for (const ng of ngrams)
    if (model.vocabulary.hasOwnProperty(ng))
      counts[ng] = (counts[ng] || 0) + 1;
  const vec = new Array(model.idf.length).fill(0);
  for (const [ng, cnt] of Object.entries(counts))
    vec[model.vocabulary[ng]] = (cnt as number) * model.idf[model.vocabulary[ng]];
  const norm = Math.sqrt(vec.reduce((s: number, v: number) => s + v * v, 0)) || 1;
  for (let i = 0; i < vec.length; i++) vec[i] /= norm;
  const score = vec.reduce((s: number, v: number, i: number) => s + v * model.coef[i], 0) + model.intercept;
  const prob = sigmoid(score);
  const urgent = prob > 0.5;
  const confidence = urgent ? prob : 1 - prob;
  const topSignals = Object.entries(counts)
    .map(([ng]) => ({ ng, weight: Math.abs(model.coef[model.vocabulary[ng]]) }))
    .sort((a, b) => b.weight - a.weight).slice(0, 4).map(w => w.ng);
  return { urgent, confidence: Math.round(confidence * 100), topSignals };
}

export default function Index() {
  const [input, setInput] = useState('');
  const [result, setResult] = useState<any>(null);
  const [history, setHistory] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);

  function classify(text?: string) {
    const target = (text || input).trim();
    if (!target) return;
    if (!MODEL) {
      Alert.alert('Model not loaded', 'Paste your model.json content into index.tsx where it says MODEL = null');
      return;
    }
    setLoading(true);
    setTimeout(() => {
      const res = runClassifier(target, MODEL);
      setResult({ text: target, ...res });
      setHistory((prev: any[]) => [{ text: target, ...res }, ...prev].slice(0, 20));
      setInput('');
      setLoading(false);
    }, 50);
  }

  return (
    <SafeAreaView style={styles.safe}>
      <StatusBar barStyle="dark-content" />
      <ScrollView contentContainerStyle={styles.scroll} keyboardShouldPersistTaps="handled">
        <Text style={styles.title}>Notification Classifier</Text>
        <Text style={styles.subtitle}>Test your urgency model</Text>
        {!MODEL && (
          <View style={styles.warningBox}>
            <Text style={styles.warningText}>Model not loaded. Paste your model.json content where it says MODEL = null.</Text>
          </View>
        )}
        <View style={styles.inputRow}>
          <TextInput style={styles.input} placeholder="Type a notification..." placeholderTextColor="#999" value={input} onChangeText={setInput} multiline />
          <TouchableOpacity style={styles.btn} onPress={() => classify()} disabled={loading}>
            {loading ? <ActivityIndicator color="#fff" size="small" /> : <Text style={styles.btnText}>Go</Text>}
          </TouchableOpacity>
        </View>
        {result && (
          <View style={[styles.resultCard, result.urgent ? styles.urgentCard : styles.safeCard]}>
            <View style={styles.resultRow}>
              <Text style={styles.resultText} numberOfLines={2}>{result.text}</Text>
              <View style={[styles.badge, result.urgent ? styles.urgentBadge : styles.safeBadge]}>
                <Text style={[styles.badgeText, result.urgent ? styles.urgentBadgeText : styles.safeBadgeText]}>{result.urgent ? 'URGENT' : 'NOT URGENT'}</Text>
              </View>
            </View>
            <View style={styles.confRow}>
              <Text style={styles.confLabel}>Confidence</Text>
              <View style={styles.barBg}><View style={[styles.barFill, { width: result.confidence + '%', backgroundColor: result.urgent ? '#E24B4A' : '#639922' }]} /></View>
              <Text style={styles.confPct}>{result.confidence}%</Text>
            </View>
            {result.topSignals.length > 0 && <Text style={styles.signals}>signals: {result.topSignals.join(', ')}</Text>}
          </View>
        )}
        <Text style={styles.sectionLabel}>Try an example</Text>
        <View style={styles.chips}>
          {EXAMPLES.map((ex, i) => (
            <TouchableOpacity key={i} style={styles.chip} onPress={() => classify(ex)}>
              <Text style={styles.chipText}>{ex}</Text>
            </TouchableOpacity>
          ))}
        </View>
        {history.length > 0 && (
          <>
            <Text style={styles.sectionLabel}>History</Text>
            {history.map((item, i) => (
              <View key={i} style={styles.historyRow}>
                <Text style={styles.historyText} numberOfLines={1}>{item.text}</Text>
                <View style={[styles.badge, item.urgent ? styles.urgentBadge : styles.safeBadge]}>
                  <Text style={[styles.badgeText, item.urgent ? styles.urgentBadgeText : styles.safeBadgeText]}>{item.urgent ? 'URGENT' : 'SAFE'} · {item.confidence}%</Text>
                </View>
              </View>
            ))}
          </>
        )}
      </ScrollView>
    </SafeAreaView>
  );
}

